export default {
    namespaced: true,
    state: {
        door_list: {
            rows: [],
            columns: [ 'id','acc_name', 'dbname', 'device', 'inout', 'login', 'password', 'status'],
            col: []
        },
        device_status: {}
    },
    actions: {
        async fetch_Door(ctx) {
            const res = await fetch(ctx.rootState.hostname + '/SkudDoors');
            const res_data = await res.json();
            ctx.commit('Updatedoor_list', res_data);
        },
        async checkAllDevicesStatus(ctx) {
            try {
                const res = await fetch(ctx.rootState.hostname + '/SkudDoors/checkAllStatus');
                const statusData = await res.json();
                ctx.commit('UpdateDeviceStatus', statusData);
                return statusData;
            } catch (error) {
                console.error('Device status check error:', error);
                return [];
            }
        },
        async checkDeviceStatus(ctx, doorId) {
            try {
                const res = await fetch(ctx.rootState.hostname + `/SkudDoors/checkStatus/${doorId}`);
                const statusData = await res.json();
                return statusData;
            } catch (error) {
                console.error('Device status check error:', error);
                return { status: 'offline', isOnline: false };
            }
        }
    },
    mutations: {
        Updatedoor_list(state, data) {
            state.door_list.rows = data;
        },
        door_row_delete(state, index) {
            state.door_list.rows.splice(parseInt(index), 1);
        },
        UpdateDeviceStatus(state, statusData) {
            const statusMap = {};
            statusData.forEach(item => {
                statusMap[item.id] = item;
            });
            state.device_status = statusMap;
            
            // Door list'ga status ni qo'shish
            state.door_list.rows = state.door_list.rows.map(door => {
                const status = statusMap[door.id];
                return {
                    ...door,
                    status: status ? (status.isOnline ? 'online' : 'offline') : 'unknown'
                };
            });
        }
    },
    getters: {
        get_door_list(state) {
            return state.door_list;
        },
        get_device_status(state) {
            return state.device_status;
        }
    }
}