export default {
    state: {
        hikvision_camera_t: {
            rows: [],
            columns: ['name', 'ip', 'username', 'password'],
            col: []
        },
    },
    actions: {
        async fetch_hikvision_camera_t(ctx) {
            const res = await fetch(ctx.rootState.hostname + '/TegirmonHikvisionCamera');
            const res_data = await res.json();
            ctx.commit('update_hikvision_camera_t', res_data);
        },
    },
    mutations: {
        update_hikvision_camera_t(state, data) {
            state.hikvision_camera_t.rows = data;
        },
        hikvision_camera_t_delete_row(state, index) {
            state.hikvision_camera_t.rows.splice(parseInt(index), 1);
        },
        update_hikvision_camera_t_column(state, data) {
            state.hikvision_camera_t.col = data;
            state.hikvision_camera_t.columns = data.column_default_obj
                .filter(obj => { return obj.status === true })
                .map(({ name }) => name);
        },
    },
    getters: {
        all_hikvision_camera_t(state) {
            return state.hikvision_camera_t;
        }
    }
}
